'use client';

import { useState, useMemo, useEffect } from 'react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Search, Download, ChevronDown, Plus, X, Trash2, Columns } from 'lucide-react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { format } from 'date-fns';
import { v4 as uuidv4 } from 'uuid';

type LeadStatus = 'new' | 'contacted' | 'qualified' | 'lost';

type Column = {
  id: string;
  header: string;
  accessor: string;
  type: 'text' | 'date' | 'tags' | 'status';
};

type Lead = {
  id: string;
  name: string;
  phone: string;
  email: string;
  createdAt: Date;
  tags: string[];
  status: LeadStatus;
  [key: string]: any; // For dynamic columns
};

const mockLeads: Lead[] = [
  {
    id: '1',
    name: 'John Doe',
    phone: '(123) 456-7890',
    email: 'john@example.com',
    createdAt: new Date('2023-11-28'),
    tags: ['Premium', 'VIP'],
    status: 'new',
  },
  {
    id: '2',
    name: 'Jane Smith',
    phone: '(234) 567-8901',
    email: 'jane@example.com',
    createdAt: new Date('2023-11-27'),
    tags: ['Standard'],
    status: 'contacted',
  },
  {
    id: '3',
    name: 'Bob Johnson',
    phone: '(345) 678-9012',
    email: 'bob@example.com',
    createdAt: new Date('2023-11-26'),
    tags: ['VIP'],
    status: 'qualified'
  }
];

const STORAGE_KEY = 'excel_leads';
const COLUMNS_KEY = 'excel_columns';

const defaultColumns: Column[] = [
  { id: 'name', header: 'Name', accessor: 'name', type: 'text' },
  { id: 'phone', header: 'Phone', accessor: 'phone', type: 'text' },
  { id: 'email', header: 'Email', accessor: 'email', type: 'text' },
  { id: 'createdAt', header: 'Created At', accessor: 'createdAt', type: 'date' },
  { id: 'tags', header: 'Tags', accessor: 'tags', type: 'tags' },
  { id: 'status', header: 'Status', accessor: 'status', type: 'status' },
];

export default function LeadsPage() {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [tagFilter, setTagFilter] = useState<string>('all');
  const [leads, setLeads] = useState<Lead[]>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved).map((lead: any) => ({
        ...lead,
        createdAt: new Date(lead.createdAt)
      })) : mockLeads;
    }
    return mockLeads;
  });
  
  const [columns, setColumns] = useState<Column[]>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem(COLUMNS_KEY);
      return saved ? JSON.parse(saved) : defaultColumns;
    }
    return defaultColumns;
  });
  
  const [newColumnName, setNewColumnName] = useState('');
  const [isAddingColumn, setIsAddingColumn] = useState(false);

  // Save to localStorage whenever leads or columns change
  useEffect(() => {
    if (typeof window !== 'undefined') {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(leads));
      localStorage.setItem(COLUMNS_KEY, JSON.stringify(columns));
    }
  }, [leads, columns]);

  const updateLeadField = (leadId: string, field: string, value: any) => {
    setLeads(leads.map(lead => 
      lead.id === leadId ? { ...lead, [field]: value } : lead
    ));
  };

  const updateLeadStatus = (leadId: string, newStatus: LeadStatus) => {
    updateLeadField(leadId, 'status', newStatus);
  };

  const filteredLeads = useMemo(() => {
    return leads.filter(lead => {
      const matchesSearch = 
        lead.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        lead.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
        lead.phone.includes(searchTerm);
      
      const matchesStatus = statusFilter === 'all' || lead.status === statusFilter;
      const matchesTag = tagFilter === 'all' || lead.tags.includes(tagFilter);
      
      return matchesSearch && matchesStatus && matchesTag;
    });
  }, [leads, searchTerm, statusFilter, tagFilter]);

  const allTags = useMemo(() => {
    const tags = new Set<string>();
    leads.forEach(lead => {
      lead.tags.forEach(tag => tags.add(tag));
    });
    return Array.from(tags);
  }, [leads]);

  const exportToCSV = () => {
    const headers = ['Name', 'Phone', 'Email', 'Created At', 'Tags', 'Status'];
    const csvContent = [
      headers.join(','),
      ...filteredLeads.map(lead => 
        [
          `"${lead.name}"`,
          `"${lead.phone}"`,
          `"${lead.email}"`,
          `"${format(lead.createdAt, 'yyyy-MM-dd')}"`,
          `"${lead.tags.join(', ')}"`,
          `"${lead.status}"`
        ].join(',')
      )
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `leads-${format(new Date(), 'yyyy-MM-dd')}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const addNewColumn = () => {
    if (!newColumnName.trim()) return;
    const newColumn = {
      id: newColumnName.toLowerCase().replace(/\s+/g, '_'),
      header: newColumnName,
      accessor: newColumnName.toLowerCase().replace(/\s+/g, '_'),
      type: 'text' as const
    };
    
    setColumns([...columns, newColumn]);
    setNewColumnName('');
    setIsAddingColumn(false);
    
    // Add the new column to all leads
    setLeads(leads.map(lead => ({
      ...lead,
      [newColumn.accessor]: ''
    })));
  };

  const removeColumn = (columnId: string) => {
    if (['name', 'email', 'phone', 'createdAt', 'tags', 'status'].includes(columnId)) {
      return; // Prevent removing default columns
    }
    setColumns(columns.filter(col => col.id !== columnId));
  };

  const addNewRow = () => {
    const newLead: Lead = {
      id: uuidv4(),
      name: '',
      phone: '',
      email: '',
      createdAt: new Date(),
      tags: [],
      status: 'new',
    };
    
    // Initialize all custom columns with empty values
    columns.forEach(col => {
      if (!['name', 'email', 'phone', 'createdAt', 'tags', 'status'].includes(col.id)) {
        newLead[col.id] = '';
      }
    });
    
    setLeads([newLead, ...leads]);
  };

  return (
    <div className="p-6">
      <div className="flex flex-col gap-4 mb-6">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div className="flex-1 flex flex-col sm:flex-row items-start sm:items-center gap-4 w-full">
            <div className="relative w-full sm:w-96">
              <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-gray-500" />
              <Input
                type="text"
                placeholder="Search leads..."
                className="pl-10"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            
            <div className="relative w-full sm:w-48">
              <select
                className="flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm ring-offset-background focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2"
                value={tagFilter}
                onChange={(e) => setTagFilter(e.target.value)}
              >
                <option value="all">All Tags</option>
                {allTags.map(tag => (
                  <option key={tag} value={tag}>{tag}</option>
                ))}
              </select>
            </div>
          </div>
          
          <div className="flex items-center gap-2 w-full sm:w-auto">
            <Button 
              variant="outline" 
              className="flex items-center gap-2"
              onClick={() => setIsAddingColumn(!isAddingColumn)}
            >
              <Columns className="h-4 w-4" />
              {isAddingColumn ? 'Cancel' : 'Add Column'}
            </Button>
            
            <Button onClick={addNewRow} className="flex items-center gap-2">
              <Plus className="h-4 w-4" />
              Add Row
            </Button>
            
            <Button onClick={exportToCSV} variant="outline" className="ml-2">
              <Download className="mr-2 h-4 w-4" />
              Export
            </Button>
          </div>
        </div>
        
        {isAddingColumn && (
          <div className="flex items-center gap-2 p-4 bg-gray-50 rounded-lg">
            <Input
              type="text"
              placeholder="Column name"
              value={newColumnName}
              onChange={(e) => setNewColumnName(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && addNewColumn()}
              className="max-w-xs"
            />
            <Button onClick={addNewColumn} disabled={!newColumnName.trim()}>
              Add
            </Button>
          </div>
        )}
      </div>

      <div className="border border-gray-200 rounded-lg overflow-hidden">
        <div className="bg-gray-50 px-6 py-3 border-b border-gray-200 flex justify-between items-center">
          <h3 className="text-sm font-medium text-gray-700">Leads</h3>
        </div>
        <div className="overflow-x-auto">
          <Table className="min-w-full">
            <TableHeader className="bg-white">
              <TableRow className="border-b border-gray-200">
                {columns.map((column) => (
                  <TableHead 
                    key={column.id}
                    className="text-xs font-medium text-gray-500 uppercase tracking-wider relative group"
                  >
                    <div className="flex items-center justify-between">
                      <span>{column.header}</span>
                      {!['name', 'email', 'phone', 'createdAt', 'tags', 'status'].includes(column.id) && (
                        <button 
                          onClick={() => removeColumn(column.id)}
                          className="opacity-0 group-hover:opacity-100 text-gray-400 hover:text-red-500 ml-2"
                          title="Remove column"
                        >
                          <X className="h-3 w-3" />
                        </button>
                      )}
                    </div>
                  </TableHead>
                ))}
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredLeads.length > 0 ? (
                filteredLeads.map((lead, index) => (
                  <TableRow 
                    key={lead.id} 
                    className={`${index % 2 === 0 ? 'bg-white' : 'bg-gray-50'} hover:bg-gray-50 border-b border-gray-100`}
                  >
                    {columns.map((column) => {
                      const value = lead[column.accessor];
                      
                      return (
                        <TableCell 
                          key={`${lead.id}-${column.id}`}
                          className="px-4 py-3 text-sm text-gray-900 align-top"
                        >
                          {column.type === 'status' ? (
                            <DropdownMenu>
                              <DropdownMenuTrigger className="focus:outline-none w-full text-left">
                                <div 
                                  className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-medium cursor-pointer ${
                                    value === 'new' 
                                      ? 'bg-blue-100 text-blue-800 hover:bg-blue-200' 
                                      : value === 'contacted' 
                                        ? 'bg-yellow-100 text-yellow-800 hover:bg-yellow-200' 
                                        : value === 'qualified' 
                                          ? 'bg-green-100 text-green-800 hover:bg-green-200' 
                                          : 'bg-red-100 text-red-800 hover:bg-red-200'
                                  }`}
                                >
                                  {String(value).charAt(0).toUpperCase() + String(value).slice(1)}
                                  <ChevronDown className="ml-1 h-3 w-3" />
                                </div>
                              </DropdownMenuTrigger>
                              <DropdownMenuContent align="start" className="w-40">
                                <DropdownMenuItem 
                                  onSelect={() => updateLeadField(lead.id, column.accessor, 'new')}
                                  className="cursor-pointer"
                                >
                                  New
                                </DropdownMenuItem>
                                <DropdownMenuItem 
                                  onSelect={() => updateLeadField(lead.id, column.accessor, 'contacted')}
                                  className="cursor-pointer"
                                >
                                  Contacted
                                </DropdownMenuItem>
                                <DropdownMenuItem 
                                  onSelect={() => updateLeadField(lead.id, column.accessor, 'qualified')}
                                  className="cursor-pointer"
                                >
                                  Qualified
                                </DropdownMenuItem>
                                <DropdownMenuItem 
                                  onSelect={() => updateLeadField(lead.id, column.accessor, 'lost')}
                                  className="cursor-pointer text-red-600"
                                >
                                  Lost
                                </DropdownMenuItem>
                              </DropdownMenuContent>
                            </DropdownMenu>
                          ) : column.type === 'tags' ? (
                            <div className="flex flex-wrap gap-1">
                              {Array.isArray(value) ? value.map((tag: string) => (
                                <span 
                                  key={tag} 
                                  className="px-2 py-0.5 text-xs rounded-full bg-blue-50 text-blue-700 border border-blue-100"
                                >
                                  {tag}
                                </span>
                              )) : null}
                            </div>
                          ) : column.type === 'date' ? (
                            <div className="whitespace-nowrap">
                              {value ? format(new Date(value), 'MMM d, yyyy') : ''}
                            </div>
                          ) : (
                            <input
                              type="text"
                              className="w-full p-1 border border-transparent rounded hover:border-gray-300 focus:border-blue-500 focus:ring-1 focus:ring-blue-500 focus:outline-none"
                              value={value || ''}
                              onChange={(e) => updateLeadField(lead.id, column.accessor, e.target.value)}
                              onClick={(e) => e.stopPropagation()}
                            />
                          )}
                        </TableCell>
                      );
                    })}
                    <td className="px-2 py-3">
                      <button
                        onClick={() => {
                          if (confirm('Are you sure you want to delete this row?')) {
                            setLeads(leads.filter(l => l.id !== lead.id));
                          }
                        }}
                        className="text-gray-400 hover:text-red-500"
                        title="Delete row"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </TableRow>
                ))
              ) : (
                <TableRow>
                  <TableCell colSpan={columns.length + 1} className="px-6 py-8 text-center text-sm text-gray-500">
                    No leads found. Click "Add Row" to create a new one.
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </div>
      </div>
    </div>
  );
}